"""Aggregate committed per-platform metrics into the BENCHMARK.md tables.

Reads every ``benchmarks/metrics/<platform>.json`` and regenerates the
cross-platform summary table, writing it between marker comments in
BENCHMARK.md so the surrounding prose stays hand-authored::

    <!-- BEGIN:cross-platform (generated by benchmarks/aggregate.py — do not edit) -->
    ...generated table...
    <!-- END:cross-platform -->

Merging parallel per-platform branches is therefore conflict-free: each branch
adds its own ``metrics/<platform>.json`` (and does NOT run this); after merging
to ``main``, run this once there to refresh the generated table.

Usage::

    python -m benchmarks.aggregate            # refresh BENCHMARK.md + SUMMARY.md
    python -m benchmarks.aggregate --check     # non-zero exit if out of date
"""
from __future__ import annotations

import argparse
import glob
import json
import os

from benchmarks.platforms import PLATFORMS

BEGIN = ("<!-- BEGIN:cross-platform (generated by benchmarks/aggregate.py "
         "— do not edit) -->")
END = "<!-- END:cross-platform -->"

# Representative engine preference per validator (avoid double-counting the
# multiple engines benchmark_a runs for the same validator).
_ULT_ENGINES = ("onnx", "tensorrt", "pytorch", "coreml")
_YV_ENGINES = ("numpy", "tensorrt", "torch", "hailo", "tflite")


def _pick(rows, validator, engines):
    by_engine = {r["engine"]: r for r in rows if r["validator"] == validator}
    for e in engines:
        if e in by_engine:
            return by_engine[e]
    return next(iter(by_engine.values()), None)


def _fmt(x, nd=4):
    return "—" if x is None else f"{x:.{nd}f}"


def _platform_summary(platform, rows):
    """One summary row dict for a platform's rows at a single precision."""
    variants = {}
    for r in rows:
        variants.setdefault((r["variant"], r["task"]), []).append(r)

    det = sorted({v for (v, t) in variants if t == "detect"})
    seg = sorted({v for (v, t) in variants if t == "segment"})
    precisions = sorted({r["precision"] for r in rows})

    base_val = PLATFORMS[platform]["baseline_validator"]
    box_deltas, mask_deltas = [], []
    rep_box = rep_mask = rep_fps = None
    for (variant, task), vr in variants.items():
        ult = _pick(vr, "ultralytics", _ULT_ENGINES)
        yv = _pick(vr, "yolo-validator", _YV_ENGINES)
        if ult and yv and ult["box_ap"] is not None and yv["box_ap"] is not None:
            box_deltas.append(ult["box_ap"] - yv["box_ap"])
            if ult["mask_ap"] is not None and yv["mask_ap"] is not None:
                mask_deltas.append(ult["mask_ap"] - yv["mask_ap"])
        base = _pick(vr, base_val, _ULT_ENGINES if base_val == "ultralytics" else _YV_ENGINES)
        if base and variant == "yolov8n":
            rep_box, rep_fps = base["box_ap"], base["fps_wall"]
        if base and variant == "yolov8n-seg":
            rep_mask = base["mask_ap"]
    return {
        "platform": platform,
        "precision": "/".join(precisions),
        "baseline": base_val,
        "n_det": len(det), "n_seg": len(seg),
        "rep_box": rep_box, "rep_mask": rep_mask, "rep_fps": rep_fps,
        "proxy_box": max(box_deltas) if box_deltas else None,
        "proxy_mask": max(mask_deltas) if mask_deltas else None,
    }


def build_table():
    metrics = sorted(glob.glob("benchmarks/metrics/*.json"))
    summaries = []
    for fn in metrics:
        data = json.load(open(fn, encoding="utf-8"))
        p = data.get("platform")
        if p not in PLATFORMS:
            continue
        # A platform file may carry several precisions (e.g. onnx-cuda FP32+FP16);
        # emit one summary row per precision rather than collapsing them.
        by_precision = {}
        for r in data["rows"]:
            # EdgeFirst standardizes on the classical (end2end=False) head; the
            # end2end (NMS-free) variants are excluded from the summary (see
            # YOLO26.md for the head-to-head that justifies this).
            if "-nmsfree" in r["variant"]:
                continue
            by_precision.setdefault(r["precision"], []).append(r)
        for precision in sorted(by_precision):
            summaries.append(_platform_summary(p, by_precision[precision]))
    # registry order, then precision, for stable output
    order = list(PLATFORMS)
    summaries.sort(key=lambda s: (order.index(s["platform"]), s["precision"]))

    lines = [
        "| Platform | precision | baseline | det | seg | yolov8n box | yolov8n-seg mask | proxy box Δ | proxy mask Δ | yolov8n FPS |",
        "|---|---|---|--:|--:|--:|--:|--:|--:|--:|",
    ]
    for s in summaries:
        pb = "—" if s["proxy_box"] is None else f"≤{s['proxy_box']*100:.2f} pp"
        pm = "—" if s["proxy_mask"] is None else f"≤{s['proxy_mask']*100:.2f} pp"
        fps = "—" if s["rep_fps"] is None else f"{s['rep_fps']:.1f}"
        lines.append(
            f"| {s['platform']} | {s['precision']} | {s['baseline']} | "
            f"{s['n_det']} | {s['n_seg']} | {_fmt(s['rep_box'])} | "
            f"{_fmt(s['rep_mask'])} | {pb} | {pm} | {fps} |")
    note = ("\n*Baseline = Ultralytics/Vendor workflow (validator column); "
            "proxy Δ = yolo-validator vs the Ultralytics baseline where both "
            "run (one-sided). Generated from `benchmarks/metrics/` — "
            f"{len(summaries)} platform(s).*")
    return "\n".join(lines) + "\n" + note


def _splice(doc, table):
    block = f"{BEGIN}\n{table}\n{END}"
    if BEGIN in doc and END in doc:
        pre = doc[:doc.index(BEGIN)]
        post = doc[doc.index(END) + len(END):]
        return pre + block + post
    raise SystemExit(
        "BENCHMARK.md is missing the cross-platform markers:\n"
        f"  {BEGIN}\n  {END}\nAdd them where the generated table should go.")


def main():
    ap = argparse.ArgumentParser(description=__doc__)
    ap.add_argument("--check", action="store_true",
                    help="exit non-zero if BENCHMARK.md is out of date")
    a = ap.parse_args()

    table = build_table()
    doc = open("BENCHMARK.md", encoding="utf-8").read()
    new = _splice(doc, table)

    if a.check:
        if new != doc:
            raise SystemExit("BENCHMARK.md cross-platform table is stale — "
                             "run `python -m benchmarks.aggregate`")
        print("BENCHMARK.md up to date")
        return

    with open("BENCHMARK.md", "w", encoding="utf-8") as f:
        f.write(new)
    print("regenerated BENCHMARK.md cross-platform table")


if __name__ == "__main__":
    main()
